import { DynamoDBClient, UpdateCommand } from "@aws-sdk/client-dynamodb";

// Configure AWS SDK v3 client
const ddbClient = new DynamoDBClient({ region: process.env.AWS_REGION });

// Environment variables for configuration
const ORDERS_TABLE_NAME = process.env.ORDERS_TABLE_NAME || "OrdersTable";
// Replace with your actual payment gateway API endpoint.
// For demonstration, using a dummy public API that echoes POST requests.
const PAYMENT_API_ENDPOINT = process.env.PAYMENT_API_ENDPOINT || "https://jsonplaceholder.typicode.com/posts";

/**
 * Simulates calling an external payment API.
 * In a real-world scenario, you would integrate with a payment gateway like Stripe, PayPal, etc.
 * This example uses a dummy public endpoint for demonstration purposes.
 * It includes a timeout mechanism for the API call.
 *
 * @param {string} orderId The ID of the order to process.
 * @param {number} amount The amount to charge for the order.
 * @returns {Promise<{ success: boolean, transactionId?: string, errorMessage?: string, rawResponse?: any }>}
 */
async function callPaymentApi(orderId, amount) {
    console.log(`Calling payment API for order ${orderId} with amount $${amount}...`);

    try {
        const requestBody = JSON.stringify({
            orderId,
            amount,
            currency: 'USD',
            // Add any other required payment details or metadata
        });

        // Use AbortController for request timeout in Node.js `fetch`
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 5000); // 5 seconds timeout for API call

        const response = await fetch(PAYMENT_API_ENDPOINT, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                // IMPORTANT: Add your actual payment API key/authorization header here
                // Example: 'Authorization': `Bearer ${process.env.PAYMENT_API_KEY}`
            },
            body: requestBody,
            signal: controller.signal // Apply the AbortController signal
        });

        clearTimeout(timeoutId); // Clear timeout if request completes before timeout

        if (response.ok) {
            const data = await response.json();
            // For a real payment API, `data` would contain actual transaction details.
            // Here, we generate a mock transaction ID for demonstration.
            const transactionId = `txn_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
            console.log(`Payment successful for order ${orderId}. Mock Transaction ID: ${transactionId}`);
            return { success: true, transactionId: transactionId, rawResponse: data };
        } else {
            const errorBody = await response.text();
            console.error(`Payment API error for order ${orderId}: Status ${response.status}, Body: ${errorBody}`);
            return { success: false, errorMessage: `Payment API failed: Status ${response.status}, Body: ${errorBody}` };
        }
    } catch (error) {
        if (error.name === 'AbortError') {
            console.error(`Payment API call timed out for order ${orderId}.`, error);
            return { success: false, errorMessage: `Payment API call timed out after 5 seconds.` };
        }
        console.error(`Network or unexpected error calling payment API for order ${orderId}:`, error);
        return { success: false, errorMessage: `Payment API call failed due to network error: ${error.message}` };
    }
}

/**
 * Updates the order status and payment details in the DynamoDB table.
 *
 * @param {string} orderId The ID of the order to update.
 * @param {string} status The new status of the order (e.g., 'PAID', 'PAYMENT_FAILED').
 * @param {object} paymentDetails Additional payment-related details to store.
 * @returns {Promise<void>}
 */
async function updateOrderInDynamoDB(orderId, status, paymentDetails) {
    console.log(`Updating DynamoDB for order ${orderId} with status ${status}...`);

    const params = {
        TableName: ORDERS_TABLE_NAME,
        Key: {
            // Assuming 'orderId' is the partition key of your DynamoDB table.
            // Ensure this attribute name matches your table schema.
            'orderId': { S: orderId },
        },
        UpdateExpression: "SET OrderStatus = :status, PaymentDetails = :paymentDetails, UpdatedAt = :updatedAt",
        ExpressionAttributeValues: {
            ":status": { S: status },
            // Store paymentDetails as a JSON string to keep it as a single attribute
            ":paymentDetails": { S: JSON.stringify(paymentDetails) },
            ":updatedAt": { S: new Date().toISOString() },
        },
        ReturnValues: "UPDATED_NEW", // Returns the new values of the updated attributes
    };

    try {
        await ddbClient.send(new UpdateCommand(params));
        console.log(`DynamoDB updated successfully for order ${orderId}.`);
    } catch (error) {
        console.error(`Error updating DynamoDB for order ${orderId}:`, error);
        // Re-throw the error so it can be caught by the SQS message processing block,
        // which will mark the message for retry.
        throw error;
    }
}

/**
 * Main Lambda handler function for SQS events.
 * Processes messages from an SQS queue, calls a payment API, and updates DynamoDB.
 * Utilizes Promise.allSettled for concurrent processing of SQS messages within a batch
 * and gracefully handles individual message failures by returning `batchItemFailures`.
 *
 * @param {import('aws-lambda').SQSEvent} event The SQS event object containing messages.
 * @returns {Promise<import('aws-lambda').SQSBatchResponse>} A response indicating which messages failed,
 *                                                           allowing SQS to retry only those.
 */
export const handler = async (event) => {
    // Process all SQS records concurrently using Promise.allSettled.
    // This allows the Lambda function to continue processing other messages even if one fails,
    // and gathers the outcome of all processing attempts.
    const processingPromises = event.Records.map(async (record) => {
        const messageId = record.messageId; // Unique identifier for the SQS message
        let order; // Declare order here so it's accessible for error logging

        try {
            // Parse the order details from the SQS message body (assuming JSON format)
            order = JSON.parse(record.body);
            const { orderId, amount } = order;

            // Basic validation for critical order data
            if (!orderId || typeof amount !== 'number') {
                throw new Error('Invalid order data: missing orderId or invalid amount.');
            }

            console.log(`[MessageId: ${messageId}] Processing order ${orderId} with amount $${amount}...`);

            // Step 1: Call external payment API
            const paymentResult = await callPaymentApi(orderId, amount);
            let orderStatus;
            const paymentDetails = {
                timestamp: new Date().toISOString(),
                ...paymentResult.transactionId && { transactionId: paymentResult.transactionId },
                ...paymentResult.errorMessage && { errorMessage: paymentResult.errorMessage },
                ...paymentResult.rawResponse && { rawResponse: paymentResult.rawResponse }
            };

            if (paymentResult.success) {
                orderStatus = 'PAID';
                console.log(`[MessageId: ${messageId}] Payment successful for order ${orderId}. Transaction: ${paymentResult.transactionId}`);
            } else {
                orderStatus = 'PAYMENT_FAILED';
                console.error(`[MessageId: ${messageId}] Payment failed for order ${orderId}: ${paymentResult.errorMessage}`);
            }

            // Step 2: Update DynamoDB with payment status and details
            await updateOrderInDynamoDB(orderId, orderStatus, paymentDetails);

            console.log(`[MessageId: ${messageId}] Successfully processed order ${orderId}. Final status: ${orderStatus}`);
            // Return an object indicating success for this message
            return { status: 'fulfilled', messageId };

        } catch (error) {
            // Log the error for this specific message.
            // CloudWatch will capture these logs, allowing monitoring for issues.
            console.error(`[MessageId: ${messageId}] Failed to process message. Order ID: ${order ? order.orderId : 'N/A'}, Error:`, error);
            // Return an object indicating failure for this message, so its messageId can be collected.
            return { status: 'rejected', messageId, error: error.message };
        }
    });

    const results = await Promise.allSettled(processingPromises);

    // Filter out the messageIds of records that failed processing
    const batchItemFailures = results
        .filter(result => result.status === 'rejected')
        .map(result => ({ itemIdentifier: result.value.messageId })); // Access messageId from the resolved value of the rejected promise

    console.log(`Batch processing summary: ${event.Records.length} total messages, ${batchItemFailures.length} failures.`);

    // Return the response object for SQS batch processing.
    // SQS will automatically retry only the messages identified in `batchItemFailures`.
    return {
        batchItemFailures: batchItemFailures,
    };
};